var builder = DistributedApplication.CreateBuilder(args);

// PostgreSQL server with a persistent data volume and the pgAdmin management UI.
// Credentials are generated by Aspire and injected into referencing projects.
var postgres = builder.AddPostgres("postgres")
    .WithDataVolume("codesprint-pgdata")
    .WithPgAdmin();

// Database for the Users bounded context.
var usersDb = postgres.AddDatabase("usersdb");

builder.AddProject<Projects.CodeSprint_Users>("users-api")
       .WithReference(usersDb)
       .WaitFor(usersDb);

builder.Build().Run();
